      "path": "src/modules/projects/service.js",
      "content": "const { generateId } = require('../../lib/id');
let projectsStore = [];

async function createProject(name) {
  const project = { id: generateId(), name, tasks: [], members: [] };
  projectsStore.push(project);
  return project;
}

async function getProjectById(projectId) {
  return projectsStore.find(p => p.id === projectId);
}

module.exports = {
  createProject,
  getProjectById
};"
