let projectsStore = [];

async function addComment(projectId, taskId, text) {
  const project = projectsStore.find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  const comment = { id: generateId(), text };
  if (!task.comments) {
    task.comments = [];
  }
  task.comments.push(comment);
  return comment;
}

